mapper.select:
SELECT COALESCE(SUM(n.like_count), 0)       AS likes,
       COALESCE(SUM(n.comment_count), 0)    AS comments,
       COALESCE(SUM(n.collection_count), 0) AS collects,
       COALESCE(SUM(n.view_count), 0)       AS views,
       COUNT(*)                             AS noteCount
FROM web_note n
WHERE n.deleted = 0
  AND n.audit_status = #{auditStatus}
  AND n.create_time >= #{startTime}
  AND n.create_time < #{endTime}
